                ok = cursor.execute("SELECT @@transaction_isolation")
            else:
                ok = cursor.execute("SELECT @@tx_isolation")
            if ok:
                isolation = cursor.fetchone()[0]
                if isolation == 'REPEATABLE-READ':
                    warnings.warn(TxIsolationWarning(
